import 'package:injectable/injectable.dart'; import '../utils/app_logger.dart'; @singleton class ImageCacheService { final Map<String, dynamic> _cache = {}; void put(String url, dynamic data) { _cache[url] = data; AppLogger.debug('Image cached: $url'); } dynamic get(String url) => _cache[url]; bool has(String url) => _cache.containsKey(url); void remove(String url) => _cache.remove(url); void clear() { _cache.clear(); AppLogger.debug('Image cache cleared'); } int get size => _cache.length; }